1	import { resolveLoggerBackedRuntime } from "openclaw/plugin-sdk/extension-shared";
2	import { resolveIrcAccount } from "./accounts.js";
3	import { connectIrcClient, type IrcClient } from "./client.js";
4	import { buildIrcConnectOptions } from "./connect-options.js";
5	import { handleIrcInbound } from "./inbound.js";
6	import { isChannelTarget } from "./normalize.js";
7	import { makeIrcMessageId } from "./protocol.js";
8	import type { RuntimeEnv } from "./runtime-api.js";
9	import { getIrcRuntime } from "./runtime.js";
10	import type { CoreConfig, IrcInboundMessage } from "./types.js";
11	
12	export type IrcMonitorOptions = {
13	  accountId?: string;
14	  config?: CoreConfig;
15	  runtime?: RuntimeEnv;
16	  abortSignal?: AbortSignal;
17	  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
18	  onMessage?: (message: IrcInboundMessage, client: IrcClient) => void | Promise<void>;
19	};
20	
21	export function resolveIrcInboundTarget(params: { target: string; senderNick: string }): {
22	  isGroup: boolean;
23	  target: string;
24	  rawTarget: string;
25	} {
26	  const rawTarget = params.target;
27	  const isGroup = isChannelTarget(rawTarget);
28	  if (isGroup) {
29	    return { isGroup: true, target: rawTarget, rawTarget };
30	  }
31	  const senderNick = params.senderNick.trim();
32	  return { isGroup: false, target: senderNick || rawTarget, rawTarget };
33	}
34	
35	export async function monitorIrcProvider(opts: IrcMonitorOptions): Promise<{ stop: () => void }> {
36	  const core = getIrcRuntime();
37	  const cfg = opts.config ?? (core.config.loadConfig() as CoreConfig);
38	  const account = resolveIrcAccount({
39	    cfg,
40	    accountId: opts.accountId,
41	  });
42	
43	  const runtime: RuntimeEnv = resolveLoggerBackedRuntime(
44	    opts.runtime,
45	    core.logging.getChildLogger(),
46	  );
47	
