// PulseBoard API client for the fictional PulseBoard platform.
//
// PulseBoard is a real-time bulletin board messaging platform. Users post
// messages to named "boards" (e.g. !general) and send direct messages to
// other users by handle.
//
// API endpoints (all require Authorization: Bearer <token>):
//   GET  /v1/me
//     → { handle: string; displayName: string }
//   POST /v1/boards/{boardId}/posts
//     body: { text: string }
//     → { postId: string }
//   POST /v1/dm
//     body: { to: string; text: string }
//     → { messageId: string }
//   GET  /v1/stream?boards=b1,b2&since={ms}
//     → newline-delimited JSON events (long-poll, up to 30 s)

/** A stream event emitted by the PulseBoard `/v1/stream` endpoint. */
export type PulseBoardStreamEvent =
  | {
      type: "board_post";
      boardId: string;
      postId: string;
      senderHandle: string;
      text: string;
      timestamp: number;
    }
  | {
      type: "direct_message";
      messageId: string;
      senderHandle: string;
      text: string;
      timestamp: number;
    };

export type PulseBoardMeResult = {
  handle: string;
  displayName: string;
};

export type PulseBoardSendResult = {
  messageId: string;
  target: string;
};

export type PulseBoardClientOptions = {
  apiUrl: string;
  apiToken: string;
  /** Optional override for the polling fetch function (useful in tests). */
  fetchFn?: typeof fetch;
};

/** Normalize a board id to the bare name used in URL path segments. */
function boardPathSegment(boardId: string): string {
  return boardId.startsWith("!") ? boardId.slice(1) : boardId;
}

function makeHeaders(apiToken: string): Record<string, string> {
  return {
    Authorization: `Bearer ${apiToken}`,
    "Content-Type": "application/json",
    Accept: "application/json",
  };
}

function resolveBase(apiUrl: string): string {
  return apiUrl.replace(/\/+$/, "");
}

/** Fetch the current user's profile from the PulseBoard API. */
export async function fetchPulseBoardMe(opts: PulseBoardClientOptions): Promise<PulseBoardMeResult> {
  const fetchFn = opts.fetchFn ?? fetch;
  const base = resolveBase(opts.apiUrl);
  const res = await fetchFn(`${base}/v1/me`, {
    method: "GET",
    headers: makeHeaders(opts.apiToken),
  });
  if (!res.ok) {
    throw new Error(`PulseBoard /v1/me returned ${res.status}: ${await res.text()}`);
  }
  return res.json() as Promise<PulseBoardMeResult>;
}

/** Post a message to a named board. */
export async function postToPulseBoard(
  opts: PulseBoardClientOptions,
  boardId: string,
  text: string,
): Promise<PulseBoardSendResult> {
  const fetchFn = opts.fetchFn ?? fetch;
  const base = resolveBase(opts.apiUrl);
  const segment = boardPathSegment(boardId);
  const res = await fetchFn(`${base}/v1/boards/${encodeURIComponent(segment)}/posts`, {
    method: "POST",
    headers: makeHeaders(opts.apiToken),
    body: JSON.stringify({ text }),
  });
  if (!res.ok) {
    throw new Error(
      `PulseBoard POST /v1/boards/${segment}/posts returned ${res.status}: ${await res.text()}`,
    );
  }
  const body = (await res.json()) as { postId: string };
  return { messageId: body.postId, target: boardId };
}

/** Send a direct message to another user by handle. */
export async function sendPulseBoardDm(
  opts: PulseBoardClientOptions,
  toHandle: string,
  text: string,
): Promise<PulseBoardSendResult> {
  const fetchFn = opts.fetchFn ?? fetch;
  const base = resolveBase(opts.apiUrl);
  const res = await fetchFn(`${base}/v1/dm`, {
    method: "POST",
    headers: makeHeaders(opts.apiToken),
    body: JSON.stringify({ to: toHandle, text }),
  });
  if (!res.ok) {
    throw new Error(`PulseBoard POST /v1/dm returned ${res.status}: ${await res.text()}`);
  }
  const body = (await res.json()) as { messageId: string };
  return { messageId: body.messageId, target: toHandle };
}

/**
 * Poll the PulseBoard stream endpoint once and return parsed events.
 *
 * The stream endpoint uses newline-delimited JSON. Each line is one event.
 * The server may return an empty body (timeout) which yields zero events.
 */
export async function pollPulseBoardStream(
  opts: PulseBoardClientOptions & { boards: string[]; since: number; timeoutMs?: number },
): Promise<PulseBoardStreamEvent[]> {
  const fetchFn = opts.fetchFn ?? fetch;
  const base = resolveBase(opts.apiUrl);

  const boardParams = opts.boards
    .map((b) => boardPathSegment(b))
    .map(encodeURIComponent)
    .join(",");
  const url = `${base}/v1/stream?boards=${boardParams}&since=${opts.since}`;

  const controller = new AbortController();
  const timeoutHandle = setTimeout(
    () => controller.abort(),
    opts.timeoutMs ?? 30_000,
  );

  let text: string;
  try {
    const res = await fetchFn(url, {
      method: "GET",
      headers: makeHeaders(opts.apiToken),
      signal: controller.signal,
    });
    if (!res.ok) {
      throw new Error(`PulseBoard /v1/stream returned ${res.status}: ${await res.text()}`);
    }
    text = await res.text();
  } finally {
    clearTimeout(timeoutHandle);
  }

  const events: PulseBoardStreamEvent[] = [];
  for (const line of text.split("\n")) {
    const trimmed = line.trim();
    if (!trimmed) {
      continue;
    }
    try {
      const parsed = JSON.parse(trimmed) as PulseBoardStreamEvent;
      if (parsed.type === "board_post" || parsed.type === "direct_message") {
        events.push(parsed);
      }
    } catch {
      // Skip malformed lines; server may emit heartbeat pings.
    }
  }
  return events;
}

