/** PulseBoard board ids start with "!" (e.g. "!general"). */
export function isBoardTarget(target: string): boolean {
  return target.startsWith("!");
}

/**
 * Normalize a raw PulseBoard messaging target.
 *
 * Accepted input forms:
 *   !general              → "!general"   (board, kept as-is)
 *   board:general         → "!general"   (board, with "board:" prefix)
 *   board:!general        → "!general"   (board, redundant "!" tolerated)
 *   pulseboard:!general   → "!general"   (scheme prefix stripped)
 *   alice                 → "alice"      (user handle)
 *   user:alice            → "alice"      (user handle, "user:" prefix)
 *   pulseboard:alice      → "alice"      (scheme prefix stripped)
 *
 * Returns undefined for empty or invalid targets.
 */
export function normalizePulseboardMessagingTarget(raw: string): string | undefined {
  let target = raw.trim();
  if (!target) {
    return undefined;
  }

  // Strip scheme prefix.
  const lower = target.toLowerCase();
  if (lower.startsWith("pulseboard:")) {
    target = target.slice("pulseboard:".length).trim();
  }

  // Explicit board: prefix → ensure "!" prefix.
  if (target.toLowerCase().startsWith("board:")) {
    const rest = target.slice("board:".length).trim();
    target = rest.startsWith("!") ? rest : `!${rest}`;
  }

  // Explicit user: prefix → strip to bare handle.
  if (target.toLowerCase().startsWith("user:")) {
    target = target.slice("user:".length).trim();
  }

  if (!target || !looksLikePulseboardTargetId(target)) {
    return undefined;
  }
  return target;
}

/**
 * Return true when `raw` looks like a valid PulseBoard target id (board or handle).
 *
 * Valid board ids: "!" followed by one or more word/hyphen characters.
 * Valid handles:   one or more word/hyphen characters (no "!").
 */
export function looksLikePulseboardTargetId(raw: string): boolean {
  const trimmed = raw.trim();
  if (!trimmed) {
    return false;
  }
  // Allow "!name" for boards and plain "name" for handles.
  return /^!?[\w-]+$/u.test(trimmed);
}

/**
 * Normalize a single PulseBoard allowlist entry.
 *
 * Allowlist entries are user handles (case-insensitive). Returns the
 * normalized lowercase handle, or "" for invalid/empty input.
 */
export function normalizePulseboardAllowEntry(raw: string): string {
  let value = raw.trim().toLowerCase();
  if (!value) {
    return "";
  }
  if (value.startsWith("pulseboard:")) {
    value = value.slice("pulseboard:".length).trim();
  }
  if (value.startsWith("user:")) {
    value = value.slice("user:".length).trim();
  }
  return value.trim();
}

/** Normalize an allowlist array, dropping empty or invalid entries. */
export function normalizePulseboardAllowlist(entries?: Array<string | number>): string[] {
  return (entries ?? [])
    .map((entry) => normalizePulseboardAllowEntry(String(entry)))
    .filter(Boolean);
}

/**
 * Check whether a sender handle matches an allowlist.
 *
 * Returns `{ allowed: true, source }` when the handle (or "*") is in the list.
 */
export function resolvePulseboardAllowlistMatch(params: {
  allowFrom: string[];
  senderHandle: string;
}): { allowed: boolean; source?: string } {
  const normalized = new Set(
    params.allowFrom.map((entry) => entry.trim().toLowerCase()).filter(Boolean),
  );
  if (normalized.has("*")) {
    return { allowed: true, source: "wildcard" };
  }
  const handle = params.senderHandle.trim().toLowerCase();
  if (handle && normalized.has(handle)) {
    return { allowed: true, source: handle };
  }
  return { allowed: false };
}

