import { describe, expect, it } from "vitest";
import {
  isBoardTarget,
  looksLikePulseboardTargetId,
  normalizePulseboardAllowEntry,
  normalizePulseboardAllowlist,
  normalizePulseboardMessagingTarget,
  resolvePulseboardAllowlistMatch,
} from "./normalize.js";

describe("isBoardTarget", () => {
  it("returns true for board targets", () => {
    expect(isBoardTarget("!general")).toBe(true);
    expect(isBoardTarget("!ops")).toBe(true);
  });

  it("returns false for user handles", () => {
    expect(isBoardTarget("alice")).toBe(false);
    expect(isBoardTarget("bob-42")).toBe(false);
  });
});

describe("looksLikePulseboardTargetId", () => {
  it("accepts valid board ids", () => {
    expect(looksLikePulseboardTargetId("!general")).toBe(true);
    expect(looksLikePulseboardTargetId("!my-board_1")).toBe(true);
  });

  it("accepts valid user handles", () => {
    expect(looksLikePulseboardTargetId("alice")).toBe(true);
    expect(looksLikePulseboardTargetId("bob-42")).toBe(true);
    expect(looksLikePulseboardTargetId("user_name")).toBe(true);
  });

  it("rejects empty strings and whitespace", () => {
    expect(looksLikePulseboardTargetId("")).toBe(false);
    expect(looksLikePulseboardTargetId("   ")).toBe(false);
  });

  it("rejects targets with spaces", () => {
    expect(looksLikePulseboardTargetId("hello world")).toBe(false);
  });

  it("rejects targets with special characters", () => {
    expect(looksLikePulseboardTargetId("alice@host")).toBe(false);
    expect(looksLikePulseboardTargetId("!board/sub")).toBe(false);
  });
});

describe("normalizePulseboardMessagingTarget", () => {
  it("passes through a bare board id", () => {
    expect(normalizePulseboardMessagingTarget("!general")).toBe("!general");
  });

  it("strips pulseboard: scheme for boards", () => {
    expect(normalizePulseboardMessagingTarget("pulseboard:!general")).toBe("!general");
  });

  it("converts board: prefix to ! prefix", () => {
    expect(normalizePulseboardMessagingTarget("board:general")).toBe("!general");
    expect(normalizePulseboardMessagingTarget("board:!general")).toBe("!general");
  });

  it("passes through a bare user handle", () => {
    expect(normalizePulseboardMessagingTarget("alice")).toBe("alice");
  });

  it("strips pulseboard: scheme for user handles", () => {
    expect(normalizePulseboardMessagingTarget("pulseboard:alice")).toBe("alice");
  });

  it("strips user: prefix", () => {
    expect(normalizePulseboardMessagingTarget("user:alice")).toBe("alice");
  });

  it("trims surrounding whitespace", () => {
    expect(normalizePulseboardMessagingTarget("  !general  ")).toBe("!general");
    expect(normalizePulseboardMessagingTarget("  alice  ")).toBe("alice");
  });

  it("returns undefined for empty input", () => {
    expect(normalizePulseboardMessagingTarget("")).toBeUndefined();
    expect(normalizePulseboardMessagingTarget("   ")).toBeUndefined();
  });

  it("returns undefined for invalid targets", () => {
    expect(normalizePulseboardMessagingTarget("hello world")).toBeUndefined();
    expect(normalizePulseboardMessagingTarget("alice@host")).toBeUndefined();
  });
});

describe("normalizePulseboardAllowEntry", () => {
  it("lowercases handles", () => {
    expect(normalizePulseboardAllowEntry("Alice")).toBe("alice");
  });

  it("strips pulseboard: and user: prefixes", () => {
    expect(normalizePulseboardAllowEntry("pulseboard:alice")).toBe("alice");
    expect(normalizePulseboardAllowEntry("user:alice")).toBe("alice");
  });

  it("preserves wildcards", () => {
    expect(normalizePulseboardAllowEntry("*")).toBe("*");
  });

  it("returns empty string for empty input", () => {
    expect(normalizePulseboardAllowEntry("")).toBe("");
    expect(normalizePulseboardAllowEntry("   ")).toBe("");
  });
});

describe("normalizePulseboardAllowlist", () => {
  it("normalizes and deduplicates entries", () => {
    const result = normalizePulseboardAllowlist(["Alice", "alice", "user:Bob"]);
    expect(result).toEqual(["alice", "alice", "bob"]);
  });

  it("filters empty entries", () => {
    expect(normalizePulseboardAllowlist(["alice", "", "  "])).toEqual(["alice"]);
  });

  it("handles undefined input", () => {
    expect(normalizePulseboardAllowlist(undefined)).toEqual([]);
  });
});

describe("resolvePulseboardAllowlistMatch", () => {
  it("allows when sender handle is in the list", () => {
    const result = resolvePulseboardAllowlistMatch({
      allowFrom: ["alice", "bob"],
      senderHandle: "alice",
    });
    expect(result.allowed).toBe(true);
    expect(result.source).toBe("alice");
  });

  it("allows wildcard entries", () => {
    const result = resolvePulseboardAllowlistMatch({
      allowFrom: ["*"],
      senderHandle: "anyone",
    });
    expect(result.allowed).toBe(true);
    expect(result.source).toBe("wildcard");
  });

  it("denies when handle is not in the list", () => {
    const result = resolvePulseboardAllowlistMatch({
      allowFrom: ["alice"],
      senderHandle: "mallory",
    });
    expect(result.allowed).toBe(false);
  });

  it("performs case-insensitive matching", () => {
    const result = resolvePulseboardAllowlistMatch({
      allowFrom: ["Alice"],
      senderHandle: "alice",
    });
    expect(result.allowed).toBe(true);
  });

  it("denies when list is empty", () => {
    const result = resolvePulseboardAllowlistMatch({
      allowFrom: [],
      senderHandle: "alice",
    });
    expect(result.allowed).toBe(false);
  });
});

