import { afterEach, beforeEach, describe, expect, it } from "vitest";
import { resolvePulseboardAccount, listEnabledPulseboardAccounts } from "./accounts.js";
import type { CoreConfig } from "./types.js";

function makeConfig(overrides: Record<string, unknown> = {}): CoreConfig {
  return {
    channels: {
      pulseboard: {
        apiUrl: "https://api.pulseboard.example.com",
        apiToken: "tok-test-1234",
        handle: "myclaw-bot",
        ...overrides,
      },
    },
  } as unknown as CoreConfig;
}

describe("resolvePulseboardAccount", () => {
  it("resolves a fully configured account", () => {
    const cfg = makeConfig();
    const account = resolvePulseboardAccount({ cfg });
    expect(account.configured).toBe(true);
    expect(account.apiUrl).toBe("https://api.pulseboard.example.com");
    expect(account.handle).toBe("myclaw-bot");
    expect(account.apiToken).toBe("tok-test-1234");
    expect(account.apiTokenSource).toBe("config");
    expect(account.enabled).toBe(true);
  });

  it("marks account unconfigured when apiToken is missing", () => {
    const cfg = makeConfig({ apiToken: undefined });
    const account = resolvePulseboardAccount({ cfg });
    expect(account.configured).toBe(false);
  });

  it("marks account unconfigured when handle is missing", () => {
    const cfg = makeConfig({ handle: undefined });
    const account = resolvePulseboardAccount({ cfg });
    expect(account.configured).toBe(false);
  });

  it("marks account unconfigured when apiUrl is missing", () => {
    const cfg = makeConfig({ apiUrl: undefined });
    const account = resolvePulseboardAccount({ cfg });
    expect(account.configured).toBe(false);
  });

  it("respects enabled=false at the channel level", () => {
    const cfg = makeConfig({ enabled: false });
    const account = resolvePulseboardAccount({ cfg });
    expect(account.enabled).toBe(false);
  });

  it("falls back to env vars for default account", () => {
    const saved = {
      url: process.env.PULSEBOARD_API_URL,
      token: process.env.PULSEBOARD_API_TOKEN,
      handle: process.env.PULSEBOARD_HANDLE,
    };
