import { describe, expect, it } from "vitest";
import {
  resolvePulseboardBoardMatch,
  resolvePulseboardBoardAccessGate,
  resolvePulseboardRequireMention,
  resolvePulseboardMentionGate,
  resolvePulseboardBoardSenderAllowed,
} from "./policy.js";

describe("resolvePulseboardBoardMatch", () => {
  it("matches an explicitly configured board", () => {
    const result = resolvePulseboardBoardMatch({
      boards: { "!general": { requireMention: false } },
      boardId: "!general",
    });
    expect(result.allowed).toBe(true);
    expect(result.boardConfig?.requireMention).toBe(false);
    expect(result.hasConfiguredBoards).toBe(true);
  });

  it("matches case-insensitively", () => {
    const result = resolvePulseboardBoardMatch({
      boards: { "!General": {} },
      boardId: "!general",
    });
    expect(result.allowed).toBe(true);
  });

  it("uses wildcard config when no direct match", () => {
    const result = resolvePulseboardBoardMatch({
      boards: { "*": { requireMention: true } },
      boardId: "!random",
    });
    expect(result.allowed).toBe(true);
    expect(result.wildcardConfig?.requireMention).toBe(true);
    expect(result.boardConfig).toBeUndefined();
  });

  it("returns allowed=false with no matching config", () => {
    const result = resolvePulseboardBoardMatch({
      boards: { "!general": {} },
      boardId: "!ops",
    });
    expect(result.allowed).toBe(false);
  });

  it("returns no configured boards when boards is empty", () => {
    const result = resolvePulseboardBoardMatch({ boards: {}, boardId: "!general" });
    expect(result.hasConfiguredBoards).toBe(false);
    expect(result.allowed).toBe(false);
  });
});

describe("resolvePulseboardBoardAccessGate", () => {
  it("denies when boardPolicy is disabled", () => {
    const gate = resolvePulseboardBoardAccessGate({
      boardPolicy: "disabled",
      boardMatch: { allowed: true, hasConfiguredBoards: true },
    });
    expect(gate.allowed).toBe(false);
    expect(gate.reason).toContain("disabled");
  });

  it("denies with allowlist policy and no configured boards", () => {
    const gate = resolvePulseboardBoardAccessGate({
      boardPolicy: "allowlist",
      boardMatch: { allowed: false, hasConfiguredBoards: false },
    });
    expect(gate.allowed).toBe(false);
  });

  it("denies with allowlist policy when board not in allowlist", () => {
    const gate = resolvePulseboardBoardAccessGate({
      boardPolicy: "allowlist",
      boardMatch: { allowed: false, hasConfiguredBoards: true },
    });
    expect(gate.allowed).toBe(false);
  });

  it("allows with allowlist policy when board is allowlisted", () => {
    const gate = resolvePulseboardBoardAccessGate({
      boardPolicy: "allowlist",
      boardMatch: { allowed: true, hasConfiguredBoards: true },
    });
    expect(gate.allowed).toBe(true);
  });

  it("allows with open policy even without explicit board config", () => {
    const gate = resolvePulseboardBoardAccessGate({
      boardPolicy: "open",
      boardMatch: { allowed: false, hasConfiguredBoards: false },
    });
    expect(gate.allowed).toBe(true);
    expect(gate.reason).toBe("open");
  });

  it("denies when boardConfig.enabled is false", () => {
    const gate = resolvePulseboardBoardAccessGate({
      boardPolicy: "allowlist",
      boardMatch: {
        allowed: true,
        hasConfiguredBoards: true,
        boardConfig: { enabled: false },
      },
    });
    expect(gate.allowed).toBe(false);
    expect(gate.reason).toBe("disabled");
  });
});

describe("resolvePulseboardRequireMention", () => {
  it("uses boardConfig.requireMention when set", () => {
    expect(
      resolvePulseboardRequireMention({ boardConfig: { requireMention: false } }),
    ).toBe(false);
    expect(
      resolvePulseboardRequireMention({ boardConfig: { requireMention: true } }),
    ).toBe(true);
  });

  it("falls back to wildcardConfig.requireMention", () => {
    expect(
      resolvePulseboardRequireMention({ wildcardConfig: { requireMention: false } }),
    ).toBe(false);
  });

  it("defaults to true when neither is set", () => {
    expect(resolvePulseboardRequireMention({})).toBe(true);
  });
});

describe("resolvePulseboardMentionGate", () => {
  it("does not skip DMs", () => {
    const gate = resolvePulseboardMentionGate({
      isGroup: false,
      requireMention: true,
      wasMentioned: false,
      hasControlCommand: false,
      allowTextCommands: false,
      commandAuthorized: false,
    });
    expect(gate.shouldSkip).toBe(false);
    expect(gate.reason).toBe("direct");
  });

  it("does not skip when mention not required", () => {
    const gate = resolvePulseboardMentionGate({
      isGroup: true,
      requireMention: false,
      wasMentioned: false,
      hasControlCommand: false,
      allowTextCommands: false,
      commandAuthorized: false,
    });
    expect(gate.shouldSkip).toBe(false);
  });

  it("does not skip when bot was mentioned", () => {
    const gate = resolvePulseboardMentionGate({
      isGroup: true,
      requireMention: true,
      wasMentioned: true,
      hasControlCommand: false,
      allowTextCommands: false,
      commandAuthorized: false,
    });
    expect(gate.shouldSkip).toBe(false);
  });

  it("skips when mention required but not present", () => {
    const gate = resolvePulseboardMentionGate({
      isGroup: true,
      requireMention: true,
      wasMentioned: false,
      hasControlCommand: false,
      allowTextCommands: false,
      commandAuthorized: false,
    });
    expect(gate.shouldSkip).toBe(true);
    expect(gate.reason).toBe("missing-mention");
  });

  it("does not skip authorized control commands even without mention", () => {
    const gate = resolvePulseboardMentionGate({
      isGroup: true,
      requireMention: true,
      wasMentioned: false,
      hasControlCommand: true,
      allowTextCommands: true,
      commandAuthorized: true,
    });
    expect(gate.shouldSkip).toBe(false);
    expect(gate.reason).toBe("authorized-command");
  });
});

describe("resolvePulseboardBoardSenderAllowed", () => {
  it("allows when sender is in the inner allowFrom", () => {
    expect(
      resolvePulseboardBoardSenderAllowed({
        boardPolicy: "allowlist",
        senderHandle: "alice",
        outerAllowFrom: [],
        innerAllowFrom: ["alice"],
      }),
    ).toBe(true);
  });

  it("allows when sender is in the outer allowFrom (no inner)", () => {
    expect(
      resolvePulseboardBoardSenderAllowed({
        boardPolicy: "allowlist",
        senderHandle: "alice",
        outerAllowFrom: ["alice"],
        innerAllowFrom: [],
      }),
    ).toBe(true);
  });

  it("denies when sender is not in any allowlist", () => {
    expect(
      resolvePulseboardBoardSenderAllowed({
        boardPolicy: "allowlist",
        senderHandle: "mallory",
        outerAllowFrom: ["alice"],
        innerAllowFrom: [],
      }),
    ).toBe(false);
  });

  it("allows any sender in open policy with no allowlists", () => {
    expect(
      resolvePulseboardBoardSenderAllowed({
        boardPolicy: "open",
        senderHandle: "anyone",
        outerAllowFrom: [],
        innerAllowFrom: [],
      }),
    ).toBe(true);
  });
});

