import { resolvePulseboardAccount } from "./accounts.js";
import {
  isBoardTarget,
  normalizePulseboardMessagingTarget,
} from "./normalize.js";
import { getPulseboardRuntime } from "./runtime.js";
import type { CoreConfig } from "./types.js";
import {
  type PulseBoardClientOptions,
  type PulseBoardSendResult,
  postToPulseBoard,
  sendPulseBoardDm,
} from "./client.js";

type SendPulseboardOptions = {
  cfg?: CoreConfig;
  accountId?: string;
  replyTo?: string;
};

function recordPulseboardOutboundActivity(accountId: string): void {
  try {
    getPulseboardRuntime().channel.activity.record({
      channel: "pulseboard",
      accountId,
      direction: "outbound",
    });
  } catch (error) {
    // Swallow "runtime not initialized" errors that occur in tests or
    // standalone send calls made outside a running gateway.
    if (!(error instanceof Error) || error.message !== "PulseBoard runtime not initialized") {
      throw error;
    }
  }
}

function resolveTarget(to: string, opts?: Pick<SendPulseboardOptions, "accountId">): string {
  const normalized = normalizePulseboardMessagingTarget(to);
  if (normalized) {
    return normalized;
  }
  throw new Error(`Invalid PulseBoard target: ${to}`);
}

function makePulseboardMessageId(): string {
  return `pb-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 7)}`;
}

/**
 * Send a text message to a PulseBoard board (e.g. "!general") or user handle.
 *
 * Board targets are identified by a leading "!" (e.g. "!general").
 * All other targets are treated as direct messages to the named handle.
 */
export async function sendMessagePulseboard(
  to: string,
  text: string,
  opts: SendPulseboardOptions = {},
): Promise<PulseBoardSendResult> {
  const runtime = getPulseboardRuntime();
  const cfg = (opts.cfg ?? runtime.config.loadConfig()) as CoreConfig;
  const account = resolvePulseboardAccount({
    cfg,
    accountId: opts.accountId,
  });

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need apiUrl, apiToken, and handle in channels.pulseboard).`,
    );
  }

  const target = resolveTarget(to, opts);

  const payload = opts.replyTo ? `${text.trim()}\n\n[reply:${opts.replyTo}]` : text.trim();
  if (!payload) {
    throw new Error("Message must be non-empty for PulseBoard sends");
  }

  const clientOpts: PulseBoardClientOptions = {
    apiUrl: account.apiUrl,
    apiToken: account.apiToken,
  };

  const result = isBoardTarget(target)
    ? await postToPulseBoard(clientOpts, target, payload)
    : await sendPulseBoardDm(clientOpts, target, payload);

  recordPulseboardOutboundActivity(account.accountId);

  return {
    messageId: result.messageId || makePulseboardMessageId(),
    target,
  };
}

