import { beforeEach, describe, expect, it, vi } from "vitest";

// Mock the runtime so send.ts does not blow up outside a gateway context.
vi.mock("./runtime.js", () => ({
  getPulseboardRuntime: vi.fn(() => ({
    config: {
      loadConfig: () => ({
        channels: {
          pulseboard: {
            apiUrl: "https://api.pulseboard.example.com",
            apiToken: "tok-test",
            handle: "test-bot",
          },
        },
      }),
    },
    channel: {
      activity: { record: vi.fn() },
    },
  })),
}));

// Mock the client so no real HTTP calls are made.
vi.mock("./client.js", () => ({
  postToPulseBoard: vi.fn(async (_opts: unknown, boardId: string) => ({
    messageId: "post-abc",
    target: boardId,
  })),
  sendPulseBoardDm: vi.fn(async (_opts: unknown, handle: string) => ({
    messageId: "dm-xyz",
    target: handle,
  })),
}));

const { sendMessagePulseboard } = await import("./send.js");
const { postToPulseBoard, sendPulseBoardDm } = await import("./client.js");

describe("sendMessagePulseboard", () => {
  beforeEach(() => {
    vi.mocked(postToPulseBoard).mockClear();
    vi.mocked(sendPulseBoardDm).mockClear();
  });

  it("routes board targets to postToPulseBoard", async () => {
    const result = await sendMessagePulseboard("!general", "hello boards");
    expect(postToPulseBoard).toHaveBeenCalledOnce();
    expect(result.target).toBe("!general");
    expect(result.messageId).toBe("post-abc");
  });

  it("routes user handles to sendPulseBoardDm", async () => {
    const result = await sendMessagePulseboard("alice", "hello alice");
    expect(sendPulseBoardDm).toHaveBeenCalledOnce();
    expect(result.target).toBe("alice");
    expect(result.messageId).toBe("dm-xyz");
  });

  it("normalizes pulseboard: scheme before routing", async () => {
    const result = await sendMessagePulseboard("pulseboard:!ops", "ops message");
    expect(postToPulseBoard).toHaveBeenCalledOnce();
    const [, boardArg] = vi.mocked(postToPulseBoard).mock.calls[0]!;
    expect(boardArg).toBe("!ops");
    expect(result.target).toBe("!ops");
  });

  it("appends reply-to when provided", async () => {
    await sendMessagePulseboard("alice", "reply text", { replyTo: "dm-orig" });
    const [, , textArg] = vi.mocked(sendPulseBoardDm).mock.calls[0]!;
    expect(textArg).toContain("[reply:dm-orig]");
  });

  it("throws for invalid targets", async () => {
    await expect(sendMessagePulseboard("bad target!", "oops")).rejects.toThrow(
      "Invalid PulseBoard target",
    );
  });

  it("throws for empty message text", async () => {
    await expect(sendMessagePulseboard("alice", "   ")).rejects.toThrow(
      "Message must be non-empty",
    );
  });
});

