import { describe, expect, it, vi } from "vitest";
import type { CoreConfig } from "./types.js";

vi.mock("./client.js", () => ({
  fetchPulseBoardMe: vi.fn(),
}));

const { probePulseboard } = await import("./probe.js");
const { fetchPulseBoardMe } = await import("./client.js");

function makeConfig(overrides: Partial<{
  apiUrl: string;
  apiToken: string;
  handle: string;
}> = {}): CoreConfig {
  return {
    channels: {
      pulseboard: {
        apiUrl: overrides.apiUrl ?? "https://api.pulseboard.example.com",
        apiToken: overrides.apiToken ?? "tok-test",
        handle: overrides.handle ?? "test-bot",
      },
    },
  } as unknown as CoreConfig;
}

describe("probePulseboard", () => {
  it("returns ok=true when /v1/me succeeds", async () => {
    vi.mocked(fetchPulseBoardMe).mockResolvedValueOnce({
      handle: "test-bot",
      displayName: "Test Bot",
    });
    const result = await probePulseboard(makeConfig());
    expect(result.ok).toBe(true);
    expect(result.apiUrl).toBe("https://api.pulseboard.example.com");
    expect(result.handle).toBe("test-bot");
    expect(typeof result.latencyMs).toBe("number");
  });

  it("returns ok=false with error when fetch throws", async () => {
    vi.mocked(fetchPulseBoardMe).mockRejectedValueOnce(new Error("connection refused"));
    const result = await probePulseboard(makeConfig());
    expect(result.ok).toBe(false);
    expect(result.error).toContain("connection refused");
  });

  it("returns ok=false with missing config message when not configured", async () => {
    const result = await probePulseboard(makeConfig({ apiToken: undefined }));
    expect(result.ok).toBe(false);
    expect(result.error).toContain("missing");
    expect(fetchPulseBoardMe).not.toHaveBeenCalled();
  });

  it("notes a handle mismatch without failing", async () => {
    vi.mocked(fetchPulseBoardMe).mockResolvedValueOnce({
      handle: "other-bot",
      displayName: "Other Bot",
    });
    const result = await probePulseboard(makeConfig());
    expect(result.ok).toBe(true);
    expect((result as { note?: string }).note).toContain("mismatch");
  });
});

