import { beforeEach, describe, expect, it, vi } from "vitest";
import type { ResolvedPulseboardAccount } from "./accounts.js";
import type { CoreConfig, PulseBoardInboundMessage } from "./types.js";

// Minimal mock runtime for inbound tests.
const mockRuntime = {
  config: { loadConfig: vi.fn() },
  channel: {
    activity: { record: vi.fn() },
    commands: { shouldHandleTextCommands: vi.fn(() => false) },
    mentions: {
      buildMentionRegexes: vi.fn(() => []),
      matchesMentionPatterns: vi.fn(() => false),
    },
    text: { hasControlCommand: vi.fn(() => false) },
    routing: {
      resolveAgentRoute: vi.fn(() => ({
        agentId: "agent-1",
        sessionKey: "sess-1",
        accountId: "default",
      })),
    },
    session: {
      resolveStorePath: vi.fn(() => "/tmp/sessions"),
      readSessionUpdatedAt: vi.fn(() => undefined),
    },
    reply: {
      resolveEnvelopeFormatOptions: vi.fn(() => ({})),
      formatAgentEnvelope: vi.fn(({ body }: { body: string }) => body),
      finalizeInboundContext: vi.fn((ctx: unknown) => ctx),
    },
  },
  logging: { getChildLogger: vi.fn(() => ({ info: vi.fn(), debug: vi.fn(), error: vi.fn() })) },
};

vi.mock("./runtime.js", () => ({
  getPulseboardRuntime: vi.fn(() => mockRuntime),
}));

vi.mock("./runtime-api.js", async () => {
  const actual = await vi.importActual<typeof import("./runtime-api.js")>("./runtime-api.js");
  return {
    ...actual,
    createChannelPairingController: vi.fn(() => ({
      readStoreForDmPolicy: vi.fn(async () => []),
      issueChallenge: vi.fn(async () => {}),
    })),
    dispatchInboundReplyWithBase: vi.fn(async () => {}),
    deliverFormattedTextWithAttachments: vi.fn(async () => true),
    readStoreAllowFromForDmPolicy: vi.fn(async () => []),
    resolveAllowlistProviderRuntimeGroupPolicy: vi.fn(({ groupPolicy }: { groupPolicy: string }) => ({
      groupPolicy: groupPolicy ?? "allowlist",
      providerMissingFallbackApplied: false,
    })),
    resolveControlCommandGate: vi.fn(() => ({
      commandAuthorized: false,
      shouldBlock: false,
    })),
    resolveDefaultGroupPolicy: vi.fn(() => "allowlist"),
    resolveEffectiveAllowFromLists: vi.fn(
      ({
        allowFrom,
        groupAllowFrom,
      }: {
        allowFrom: string[];
        groupAllowFrom: string[];
        storeAllowFrom: string[];
        dmPolicy: string;
        groupAllowFromFallbackToAllowFrom: boolean;
      }) => ({
        effectiveAllowFrom: allowFrom,
        effectiveGroupAllowFrom: groupAllowFrom,
      }),
    ),
    warnMissingProviderGroupPolicyFallbackOnce: vi.fn(),
    GROUP_POLICY_BLOCKED_LABEL: { channel: "channel", direct: "direct" },
    logInboundDrop: vi.fn(),
  };
});

const { handlePulseboardInbound } = await import("./inbound.js");

function makeAccount(overrides: Partial<ResolvedPulseboardAccount> = {}): ResolvedPulseboardAccount {
  return {
    accountId: "default",
    enabled: true,
    configured: true,
    apiUrl: "https://api.pulseboard.example.com",
    apiToken: "tok-test",
    apiTokenSource: "config",
    handle: "test-bot",
    config: {
      dmPolicy: "pairing",
      boardPolicy: "allowlist",
      boards: { "!general": {} },
      boardSubscriptions: ["!general"],
      allowFrom: [],
    },
    ...overrides,
  };
}

function makeMessage(overrides: Partial<PulseBoardInboundMessage> = {}): PulseBoardInboundMessage {
  return {
    messageId: "msg-1",
    target: "!general",
    senderHandle: "alice",
    text: "test-bot hello",
    timestamp: Date.now(),
    isGroup: true,
    ...overrides,
  };
}

function makeConfig(): CoreConfig {
  return {
    channels: { pulseboard: { apiUrl: "https://api.pulseboard.example.com", apiToken: "tok", handle: "test-bot" } },
  } as unknown as CoreConfig;
}

describe("handlePulseboardInbound", () => {
  const { dispatchInboundReplyWithBase } = await import("./runtime-api.js");

  beforeEach(() => {
    vi.mocked(dispatchInboundReplyWithBase).mockClear();
  });

  it("drops empty messages without dispatching", async () => {
    await handlePulseboardInbound({
      message: makeMessage({ text: "   " }),
      account: makeAccount(),
      config: makeConfig(),
      runtime: { log: vi.fn() },
    });
    expect(dispatchInboundReplyWithBase).not.toHaveBeenCalled();
  });

  it("dispatches a valid board message", async () => {
    const account = makeAccount({
      config: {
        dmPolicy: "pairing",
        boardPolicy: "allowlist",
        boards: { "!general": {} },
        boardAllowFrom: ["*"],
      },
    });
    await handlePulseboardInbound({
      message: makeMessage({ text: "test-bot hello" }),
      account,
      config: makeConfig(),
      runtime: { log: vi.fn() },
    });
    expect(dispatchInboundReplyWithBase).toHaveBeenCalledOnce();
  });

  it("dispatches a valid DM when sender is in allowFrom", async () => {
    const { resolveEffectiveAllowFromLists } = await import("./runtime-api.js");
    vi.mocked(resolveEffectiveAllowFromLists).mockReturnValueOnce({
      effectiveAllowFrom: ["alice"],
      effectiveGroupAllowFrom: [],
    });
    await handlePulseboardInbound({
      message: makeMessage({ isGroup: false, target: "alice", senderHandle: "alice" }),
      account: makeAccount({ config: { dmPolicy: "allowlist", allowFrom: ["alice"] } }),
      config: makeConfig(),
      runtime: { log: vi.fn() },
    });
    expect(dispatchInboundReplyWithBase).toHaveBeenCalledOnce();
  });
});

