import { resolveLoggerBackedRuntime } from "openclaw/plugin-sdk/extension-shared";
import { resolvePulseboardAccount } from "./accounts.js";
import type { PulseBoardClientOptions, PulseBoardStreamEvent } from "./client.js";
import { pollPulseBoardStream } from "./client.js";
import { normalizePulseboardMessagingTarget } from "./normalize.js";
import type { RuntimeEnv } from "./runtime-api.js";
import { getPulseboardRuntime } from "./runtime.js";
import type { CoreConfig, PulseBoardInboundMessage } from "./types.js";
import { handlePulseboardInbound } from "./inbound.js";

const POLL_INTERVAL_MS = 2_000;
const LONG_POLL_TIMEOUT_MS = 28_000;

export type PulseBoardMonitorOptions = {
  accountId?: string;
  config?: CoreConfig;
  runtime?: RuntimeEnv;
  abortSignal?: AbortSignal;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
};

function makePulseboardMessageId(): string {
  return `pb-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 7)}`;
}

/** Convert a PulseBoard stream event into a normalized inbound message. */
function eventToInboundMessage(event: PulseBoardStreamEvent): PulseBoardInboundMessage | null {
  if (event.type === "board_post") {
    const target = normalizePulseboardMessagingTarget(event.boardId);
    if (!target) {
      return null;
    }
    return {
      messageId: event.postId,
      target,
      rawTarget: event.boardId,
      senderHandle: event.senderHandle,
      text: event.text,
      timestamp: event.timestamp,
      isGroup: true,
    };
  }
  if (event.type === "direct_message") {
    const handle = event.senderHandle.trim();
    if (!handle) {
      return null;
    }
    return {
      messageId: event.messageId,
      target: handle,
      senderHandle: handle,
      text: event.text,
      timestamp: event.timestamp,
      isGroup: false,
    };
  }
  return null;
}

/**
 * Start the PulseBoard provider monitor loop for one account.
 *
 * The monitor uses long-polling against the PulseBoard `/v1/stream` endpoint.
 * On each poll cycle it processes incoming events sequentially, then waits a
 * brief interval before the next poll. The loop exits when the abort signal
 * fires or when an unrecoverable error is encountered.
 */
export async function monitorPulseboardProvider(
  opts: PulseBoardMonitorOptions,
): Promise<{ stop: () => void }> {
  const core = getPulseboardRuntime();
  const cfg = opts.config ?? (core.config.loadConfig() as CoreConfig);
  const account = resolvePulseboardAccount({
    cfg,
    accountId: opts.accountId,
  });

  const runtime: RuntimeEnv = resolveLoggerBackedRuntime(
    opts.runtime,
    core.logging.getChildLogger(),
  );

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need apiUrl, apiToken, and handle in channels.pulseboard).`,
    );
  }

  const logger = core.logging.getChildLogger({
    channel: "pulseboard",
    accountId: account.accountId,
  });

  logger.info(
    `[${account.accountId}] starting PulseBoard provider (${account.apiUrl}, handle=${account.handle})`,
  );

  const clientOpts: PulseBoardClientOptions = {
    apiUrl: account.apiUrl,
    apiToken: account.apiToken,
  };

  const boards = account.config.boardSubscriptions ?? [];
  let since = Date.now();
  let stopped = false;

  const abortSignal = opts.abortSignal;

  const loop = async () => {
    while (!stopped && !(abortSignal?.aborted)) {
      try {
        const events = await pollPulseBoardStream({
          ...clientOpts,
          boards,
          since,
          timeoutMs: LONG_POLL_TIMEOUT_MS,
        });

        for (const event of events) {
          if (stopped || abortSignal?.aborted) {
            break;
          }
          // Advance the since cursor so we don't re-process events.
          if (event.timestamp > since) {
            since = event.timestamp;
          }
          // Skip messages sent by the bot itself.
          if (event.senderHandle === account.handle) {
            continue;
          }

          const message = eventToInboundMessage(event);
          if (!message) {
            continue;
          }

          core.channel.activity.record({
            channel: "pulseboard",
            accountId: account.accountId,
            direction: "inbound",
            at: message.timestamp,
          });

          await handlePulseboardInbound({
            message,
            account,
            config: cfg,
            runtime,
            statusSink: opts.statusSink,
          });
        }
      } catch (err) {
        if (stopped || abortSignal?.aborted) {
          break;
        }
        logger.error(
          `[${account.accountId}] PulseBoard poll error: ${err instanceof Error ? err.message : String(err)}`,
        );
        // Brief back-off before retrying after an error.
        await new Promise<void>((resolve) => setTimeout(resolve, POLL_INTERVAL_MS * 5));
        continue;
      }

      // Wait briefly between poll cycles to avoid hammering the server on
      // empty responses or rapid reconnects.
      await new Promise<void>((resolve) => setTimeout(resolve, POLL_INTERVAL_MS));
    }
  };

  // Start the loop without awaiting so it runs in the background.
  void loop();

  return {
    stop: () => {
      stopped = true;
    },
  };
}

