    core.logging.getChildLogger(),
  );

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need apiUrl, apiToken, and handle in channels.pulseboard).`,
    );
  }

  const logger = core.logging.getChildLogger({
    channel: "pulseboard",
    accountId: account.accountId,
  });

  logger.info(
    `[${account.accountId}] starting PulseBoard provider (${account.apiUrl}, handle=${account.handle})`,
  );

  const clientOpts: PulseBoardClientOptions = {
    apiUrl: account.apiUrl,
    apiToken: account.apiToken,
  };

  const boards = account.config.boardSubscriptions ?? [];
  let since = Date.now();
  let stopped = false;

  const abortSignal = opts.abortSignal;

  const loop = async () => {
    while (!stopped && !(abortSignal?.aborted)) {
      try {
        const events = await pollPulseBoardStream({
          ...clientOpts,
          boards,
          since,
          timeoutMs: LONG_POLL_TIMEOUT_MS,
        });

        for (const event of events) {
          if (stopped || abortSignal?.aborted) {
            break;
          }
          // Advance the since cursor so we don't re-process events.
          if (event.timestamp > since) {
            since = event.timestamp;
          }
          // Skip messages sent by the bot itself.
          if (event.senderHandle === account.handle) {
            continue;
          }

          const message = eventToInboundMessage(event);
          if (!message) {
            continue;
          }

          core.channel.activity.record({
            channel: "pulseboard",
            accountId: account.accountId,
            direction: "inbound",
            at: message.timestamp,
          });

          await handlePulseboardInbound({
            message,
            account,
            config: cfg,
            runtime,
            statusSink: opts.statusSink,
          });
        }
      } catch (err) {
        if (stopped || abortSignal?.aborted) {
          break;
        }
        logger.error(
          `[${account.accountId}] PulseBoard poll error: ${err instanceof Error ? err.message : String(err)}`,
        );
        // Brief back-off before retrying after an error.
        await new Promise<void>((resolve) => setTimeout(resolve, POLL_INTERVAL_MS * 5));
        continue;
      }

      // Wait briefly between poll cycles to avoid hammering the server on
      // empty responses or rapid reconnects.
      await new Promise<void>((resolve) => setTimeout(resolve, POLL_INTERVAL_MS));
    }
  };

  // Start the loop without awaiting so it runs in the background.
  void loop();

  return {
    stop: () => {
      stopped = true;
    },
  };
}

