    vi.mocked(pollPulseBoardStream).mockImplementation(async () => {
      if (calls++ === 0) {
        return [
          {
            type: "board_post",
            boardId: "!general",
            postId: "p1",
            senderHandle: "test-bot",
            text: "hi",
            timestamp: Date.now(),
          },
        ];
      }
      controller.abort();
      return [];
    });

    await monitorPulseboardProvider({
      config: mockCfg as unknown as import("./types.js").CoreConfig,
      abortSignal: controller.signal,
    });

    // Give the loop one tick to run.
    await new Promise<void>((r) => setTimeout(r, 50));
    expect(handlePulseboardInbound).not.toHaveBeenCalled();
  });
});

