import type { DmPolicy } from "openclaw/plugin-sdk/config-runtime";
import { DEFAULT_ACCOUNT_ID } from "openclaw/plugin-sdk/routing";
import {
  createAllowFromSection,
  createPromptParsedAllowFromForAccount,
  createStandardChannelSetupStatus,
  setSetupChannelEnabled,
} from "openclaw/plugin-sdk/setup";
import type { ChannelSetupDmPolicy, ChannelSetupWizard } from "openclaw/plugin-sdk/setup";
import { formatDocsLink } from "openclaw/plugin-sdk/setup";
import {
  listPulseboardAccountIds,
  resolveDefaultPulseboardAccountId,
  resolvePulseboardAccount,
} from "./accounts.js";
import {
  isBoardTarget,
  normalizePulseboardAllowEntry,
  normalizePulseboardMessagingTarget,
} from "./normalize.js";
import {
  pulseboardSetupAdapter,
  setPulseboardAllowFrom,
  setPulseboardBoardAccess,
  setPulseboardDmPolicy,
  updatePulseboardAccountConfig,
} from "./setup-core.js";
import type { CoreConfig } from "./types.js";

const channel = "pulseboard" as const;
const USE_ENV_FLAG = "__pulseboardUseEnv";

function parseListInput(raw: string): string[] {
  return raw
    .split(/[\n,;]+/g)
    .map((entry) => entry.trim())
    .filter(Boolean);
}

function normalizeBoardEntry(raw: string): string | null {
  const trimmed = raw.trim();
  if (!trimmed || trimmed === "*") {
    return trimmed || null;
  }
  const normalized = normalizePulseboardMessagingTarget(trimmed) ?? trimmed;
  if (isBoardTarget(normalized)) {
    return normalized;
  }
  // Automatically prepend "!" for convenience (e.g. "general" → "!general").
  return `!${normalized.replace(/^!+/, "")}`;
}

const promptPulseboardAllowFrom = createPromptParsedAllowFromForAccount<CoreConfig>({
  defaultAccountId: (cfg) => resolveDefaultPulseboardAccountId(cfg),
  noteTitle: "PulseBoard allowlist",
  noteLines: [
    "Allowlist PulseBoard DMs by sender handle.",
    "Examples:",
    "- alice",
    "- bob-42",
    "Multiple entries: comma-separated.",
  ],
  message: "PulseBoard allowFrom (handle)",
  placeholder: "alice, bob-42",
  parseEntries: (raw) => ({
    entries: parseListInput(raw)
      .map((entry) => normalizePulseboardAllowEntry(entry))
      .filter(Boolean),
  }),
  getExistingAllowFrom: ({ cfg }) => cfg.channels?.pulseboard?.allowFrom ?? [],
  applyAllowFrom: ({ cfg, allowFrom }) => setPulseboardAllowFrom(cfg, allowFrom),
});

const pulseboardDmPolicy: ChannelSetupDmPolicy = {
  label: "PulseBoard",
  channel,
  policyKey: "channels.pulseboard.dmPolicy",
  allowFromKey: "channels.pulseboard.allowFrom",
  getCurrent: (cfg) => (cfg as CoreConfig).channels?.pulseboard?.dmPolicy ?? "pairing",
  setPolicy: (cfg, policy) => setPulseboardDmPolicy(cfg as CoreConfig, policy),
  promptAllowFrom: async ({ cfg, prompter, accountId }) =>
    await promptPulseboardAllowFrom({
      cfg: cfg as CoreConfig,
      prompter,
      accountId,
    }),
};

export const pulseboardSetupWizard: ChannelSetupWizard = {
  channel,
  status: createStandardChannelSetupStatus({
    channelLabel: "PulseBoard",
    configuredLabel: "configured",
    unconfiguredLabel: "needs API URL + token + handle",
    configuredHint: "configured",
    unconfiguredHint: "needs API URL + token + handle",
    configuredScore: 1,
    unconfiguredScore: 0,
    includeStatusLine: true,
    resolveConfigured: ({ cfg }) =>
      listPulseboardAccountIds(cfg as CoreConfig).some(
        (accountId) =>
          resolvePulseboardAccount({ cfg: cfg as CoreConfig, accountId }).configured,
      ),
  }),
  introNote: {
    title: "PulseBoard setup",
    lines: [
      "PulseBoard needs an API URL, an API token, and a bot handle.",
      "Obtain an API token from your PulseBoard server admin.",
      'Set channels.pulseboard.boardPolicy="allowlist" and channels.pulseboard.boards for tighter board control.',
      "Note: boards are @mention-gated by default. Set requireMention=false per-board to disable.",
      "Env vars supported: PULSEBOARD_API_URL, PULSEBOARD_API_TOKEN, PULSEBOARD_HANDLE.",
      `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
    ],
    shouldShow: ({ cfg, accountId }) =>
      !resolvePulseboardAccount({ cfg: cfg as CoreConfig, accountId }).configured,
  },
  prepare: async ({ cfg, accountId, credentialValues, prompter }) => {
    const resolved = resolvePulseboardAccount({ cfg: cfg as CoreConfig, accountId });
    const isDefaultAccount = accountId === DEFAULT_ACCOUNT_ID;
    const envUrl = isDefaultAccount ? process.env.PULSEBOARD_API_URL?.trim() : "";
    const envToken = isDefaultAccount ? process.env.PULSEBOARD_API_TOKEN?.trim() : "";
    const envHandle = isDefaultAccount ? process.env.PULSEBOARD_HANDLE?.trim() : "";
    const envReady =
      Boolean(envUrl && envToken && envHandle) &&
      !resolved.config.apiUrl &&
      !resolved.config.apiToken &&
      !resolved.config.handle;

    if (envReady) {
      const useEnv = await prompter.confirm({
        message:
          "PULSEBOARD_API_URL, PULSEBOARD_API_TOKEN, and PULSEBOARD_HANDLE detected. Use env vars?",
        initialValue: true,
      });
      if (useEnv) {
        return {
          cfg: updatePulseboardAccountConfig(cfg as CoreConfig, accountId, { enabled: true }),
          credentialValues: { ...credentialValues, [USE_ENV_FLAG]: "1" },
        };
      }
    }

    return {
      cfg: updatePulseboardAccountConfig(cfg as CoreConfig, accountId, { enabled: true }),
      credentialValues: { ...credentialValues, [USE_ENV_FLAG]: "0" },
    };
  },
  credentials: [],
  textInputs: [
    {
      inputKey: "apiUrl",
      message: "PulseBoard API URL",
      placeholder: "https://api.pulseboard.example.com",
      currentValue: ({ cfg, accountId }) =>
        resolvePulseboardAccount({ cfg: cfg as CoreConfig, accountId }).config.apiUrl || undefined,
      shouldPrompt: ({ credentialValues }) => credentialValues[USE_ENV_FLAG] !== "1",
      validate: ({ value }) => (String(value ?? "").trim() ? undefined : "Required"),
      normalizeValue: ({ value }) => String(value).trim(),
      applySet: async ({ cfg, accountId, value }) =>
        updatePulseboardAccountConfig(cfg as CoreConfig, accountId, {
          enabled: true,
          apiUrl: value,
        }),
    },
    {
      inputKey: "token",
      message: "PulseBoard API token",
      currentValue: ({ cfg, accountId }) =>
        resolvePulseboardAccount({ cfg: cfg as CoreConfig, accountId }).config.apiToken ||
        undefined,
      shouldPrompt: ({ credentialValues }) => credentialValues[USE_ENV_FLAG] !== "1",
      validate: ({ value }) => (String(value ?? "").trim() ? undefined : "Required"),
      normalizeValue: ({ value }) => String(value).trim(),
      applySet: async ({ cfg, accountId, value }) =>
        updatePulseboardAccountConfig(cfg as CoreConfig, accountId, {
          enabled: true,
          apiToken: value,
        }),
    },
    {
      inputKey: "userId",
      message: "PulseBoard bot handle",
      placeholder: "my-claw-bot",
      currentValue: ({ cfg, accountId }) =>
        resolvePulseboardAccount({ cfg: cfg as CoreConfig, accountId }).config.handle || undefined,
      shouldPrompt: ({ credentialValues }) => credentialValues[USE_ENV_FLAG] !== "1",
      validate: ({ value }) => (String(value ?? "").trim() ? undefined : "Required"),
      normalizeValue: ({ value }) => String(value).trim(),
      applySet: async ({ cfg, accountId, value }) =>
        updatePulseboardAccountConfig(cfg as CoreConfig, accountId, {
          enabled: true,
          handle: value,
        }),
    },
    {
      inputKey: "groupChannels",
      message: "Boards to subscribe to (optional, comma-separated)",
      placeholder: "!general, !ops",
      required: false,
      applyEmptyValue: true,
      currentValue: ({ cfg, accountId }) =>
        resolvePulseboardAccount({ cfg: cfg as CoreConfig, accountId }).config.boardSubscriptions?.join(
          ", ",
        ),
      shouldPrompt: ({ credentialValues }) => credentialValues[USE_ENV_FLAG] !== "1",
      normalizeValue: ({ value }) =>
        parseListInput(String(value))
          .map((e) => normalizeBoardEntry(e))
          .filter((e): e is string => Boolean(e && e !== "*"))
          .filter((e) => isBoardTarget(e))
          .join(", "),
      applySet: async ({ cfg, accountId, value }) => {
        const subs = parseListInput(String(value))
          .map((e) => normalizeBoardEntry(e))
          .filter((e): e is string => Boolean(e && e !== "*"))
          .filter((e) => isBoardTarget(e));
        return updatePulseboardAccountConfig(cfg as CoreConfig, accountId, {
          enabled: true,
          boardSubscriptions: subs.length > 0 ? subs : undefined,
        });
      },
    },
  ],
  groupAccess: {
    label: "PulseBoard boards",
    placeholder: "!general, !ops, *",
    currentPolicy: ({ cfg, accountId }) =>
      resolvePulseboardAccount({ cfg: cfg as CoreConfig, accountId }).config.boardPolicy ??
      "allowlist",
    currentEntries: ({ cfg, accountId }) =>
      Object.keys(
        resolvePulseboardAccount({ cfg: cfg as CoreConfig, accountId }).config.boards ?? {},
      ),
    updatePrompt: ({ cfg, accountId }) =>
      Boolean(resolvePulseboardAccount({ cfg: cfg as CoreConfig, accountId }).config.boards),
    setPolicy: ({ cfg, accountId, policy }) =>
      setPulseboardBoardAccess(cfg as CoreConfig, accountId, policy, [], normalizeBoardEntry),
    resolveAllowlist: async ({ entries }) =>
      [...new Set(entries.map((e) => normalizeBoardEntry(e)).filter(Boolean))] as string[],
    applyAllowlist: ({ cfg, accountId, resolved }) =>
      setPulseboardBoardAccess(
        cfg as CoreConfig,
        accountId,
        "allowlist",
        resolved as string[],
        normalizeBoardEntry,
      ),
  },
  allowFrom: createAllowFromSection({
    helpTitle: "PulseBoard allowlist",
    helpLines: [
      "Allowlist PulseBoard DMs by sender handle.",
      "Examples:",
      "- alice",
      "- bob-42",
      "Multiple entries: comma-separated.",
    ],
    message: "PulseBoard allowFrom (handle)",
    placeholder: "alice, bob-42",
    invalidWithoutCredentialNote: "Use a PulseBoard user handle.",
    parseId: (raw) => {
      const normalized = normalizePulseboardAllowEntry(raw);
      return normalized || null;
    },
    apply: async ({ cfg, allowFrom }) => setPulseboardAllowFrom(cfg as CoreConfig, allowFrom),
  }),
  finalize: async ({ cfg, accountId, prompter }) => {
    let next = cfg as CoreConfig;

    const resolved = resolvePulseboardAccount({ cfg: next, accountId });
    if (resolved.config.boardPolicy === "allowlist") {
      const boardKeys = Object.keys(resolved.config.boards ?? {});
      if (boardKeys.length > 0) {
        const wantsMentions = await prompter.confirm({
          message: "Require @mention to reply in PulseBoard boards?",
          initialValue: true,
        });
        if (!wantsMentions) {
          const boards = resolved.config.boards ?? {};
          const patched = Object.fromEntries(
            Object.entries(boards).map(([key, value]) => [
              key,
              { ...value, requireMention: false },
            ]),
          );
          next = updatePulseboardAccountConfig(next, accountId, { boards: patched });
        }
      }
    }

    return { cfg: next };
  },
  completionNote: {
    title: "PulseBoard next steps",
    lines: [
      "Next: restart gateway and verify status.",
      "Command: openclaw channels status --probe",
      `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
    ],
  },
  dmPolicy: pulseboardDmPolicy,
  disable: (cfg) => setSetupChannelEnabled(cfg, channel, false),
};

export { pulseboardSetupAdapter };

input.content:
import { describeAccountSnapshot } from "openclaw/plugin-sdk/account-helpers";
import { formatNormalizedAllowFromEntries } from "openclaw/plugin-sdk/allow-from";
import {
  adaptScopedAccountAccessor,
  createScopedChannelConfigAdapter,
  createScopedDmSecurityResolver,
} from "openclaw/plugin-sdk/channel-config-helpers";
import {
  composeAccountWarningCollectors,
  createAllowlistProviderOpenWarningCollector,
} from "openclaw/plugin-sdk/channel-policy";
import { createChatChannelPlugin } from "openclaw/plugin-sdk/core";
import {
  createChannelDirectoryAdapter,
  createResolvedDirectoryEntriesLister,
} from "openclaw/plugin-sdk/directory-runtime";
import { runStoppablePassiveMonitor } from "openclaw/plugin-sdk/extension-shared";
import {
  createComputedAccountStatusAdapter,
  createDefaultChannelRuntimeState,
} from "openclaw/plugin-sdk/status-helpers";
import {
  listPulseboardAccountIds,
  resolveDefaultPulseboardAccountId,
  resolvePulseboardAccount,
  type ResolvedPulseboardAccount,
} from "./accounts.js";
import { PulseBoardChannelConfigSchema } from "./config-schema.js";
import { monitorPulseboardProvider } from "./monitor.js";
import {
  isBoardTarget,
  looksLikePulseboardTargetId,
  normalizePulseboardAllowEntry,
  normalizePulseboardMessagingTarget,
} from "./normalize.js";
import {
  resolvePulseboardBoardMatch,
  resolvePulseboardRequireMention,
} from "./policy.js";
import { probePulseboard } from "./probe.js";
import {
  buildBaseChannelStatusSummary,
  chunkTextForOutbound,
  createAccountStatusSink,
  DEFAULT_ACCOUNT_ID,
  getChatChannelMeta,
  PAIRING_APPROVED_MESSAGE,
  type ChannelPlugin,
} from "./runtime-api.js";
import { getPulseboardRuntime } from "./runtime.js";
import { sendMessagePulseboard } from "./send.js";
import { pulseboardSetupAdapter } from "./setup-core.js";
import { pulseboardSetupWizard } from "./setup-surface.js";
import type { CoreConfig, PulseBoardProbe } from "./types.js";

const meta = getChatChannelMeta("pulseboard");

/** Normalize a pairing target to a bare handle (no prefix). */
function normalizePairingTarget(raw: string): string {
  const normalized = normalizePulseboardAllowEntry(raw);
  return normalized.trim();
}

const listPulseboardDirectoryPeersFromConfig =
  createResolvedDirectoryEntriesLister<ResolvedPulseboardAccount>({
    kind: "user",
    resolveAccount: adaptScopedAccountAccessor(resolvePulseboardAccount),
    resolveSources: (account) => [
      account.config.allowFrom ?? [],
      account.config.boardAllowFrom ?? [],
      ...Object.values(account.config.boards ?? {}).map((b) => b?.allowFrom ?? []),
    ],
    normalizeId: (entry) => normalizePairingTarget(entry) || null,
  });

const listPulseboardDirectoryBoardsFromConfig =
  createResolvedDirectoryEntriesLister<ResolvedPulseboardAccount>({
    kind: "group",
    resolveAccount: adaptScopedAccountAccessor(resolvePulseboardAccount),
    resolveSources: (account) => [
      account.config.boardSubscriptions ?? [],
      Object.keys(account.config.boards ?? {}),
    ],
    normalizeId: (entry) => {
      const normalized = normalizePulseboardMessagingTarget(entry);
      return normalized && isBoardTarget(normalized) ? normalized : null;
    },
  });

const pulseboardConfigAdapter = createScopedChannelConfigAdapter<
  ResolvedPulseboardAccount,
  ResolvedPulseboardAccount,
  CoreConfig
>({
  sectionKey: "pulseboard",
  listAccountIds: listPulseboardAccountIds,
  resolveAccount: adaptScopedAccountAccessor(resolvePulseboardAccount),
  defaultAccountId: resolveDefaultPulseboardAccountId,
  clearBaseFields: ["name", "apiUrl", "apiToken", "apiTokenFile", "handle", "boardSubscriptions"],
  resolveAllowFrom: (account: ResolvedPulseboardAccount) => account.config.allowFrom,
  formatAllowFrom: (allowFrom) =>
    formatNormalizedAllowFromEntries({
      allowFrom,
      normalizeEntry: normalizePulseboardAllowEntry,
    }),
  resolveDefaultTo: (account: ResolvedPulseboardAccount) => account.config.defaultTo,
});

const resolvePulseboardDmPolicy = createScopedDmSecurityResolver<ResolvedPulseboardAccount>({
  channelKey: "pulseboard",
  resolvePolicy: (account) => account.config.dmPolicy,
  resolveAllowFrom: (account) => account.config.allowFrom,
  policyPathSuffix: "dmPolicy",
  normalizeEntry: (raw) => normalizePulseboardAllowEntry(raw),
});

const collectPulseboardBoardPolicyWarnings =
  createAllowlistProviderOpenWarningCollector<ResolvedPulseboardAccount>({
    providerConfigPresent: (cfg) => cfg.channels?.pulseboard !== undefined,
    resolveGroupPolicy: (account) => account.config.boardPolicy,
    buildOpenWarning: {
      surface: "PulseBoard boards",
      openBehavior: "allows all subscribed boards and senders (mention-gated)",
      remediation:
        'Prefer channels.pulseboard.boardPolicy="allowlist" with channels.pulseboard.boards',
    },
  });

const collectPulseboardSecurityWarnings = composeAccountWarningCollectors<
  ResolvedPulseboardAccount,
  {
    account: ResolvedPulseboardAccount;
    cfg: CoreConfig;
  }
>(
  collectPulseboardBoardPolicyWarnings,
  (account) =>
    !account.config.apiUrl?.startsWith("https://") &&
    "- PulseBoard API URL does not use HTTPS; traffic and credentials may be transmitted in plaintext.",
);

export const pulseboardPlugin: ChannelPlugin<ResolvedPulseboardAccount, PulseBoardProbe> =
  createChatChannelPlugin({
    base: {
      id: "pulseboard",
      meta: {
        ...meta,
        quickstartAllowFrom: true,
      },
      setup: pulseboardSetupAdapter,
      setupWizard: pulseboardSetupWizard,
      capabilities: {
        chatTypes: ["direct", "group"],
        media: true,
        blockStreaming: true,
      },
      reload: { configPrefixes: ["channels.pulseboard"] },
      configSchema: PulseBoardChannelConfigSchema,
      config: {
        ...pulseboardConfigAdapter,
        isConfigured: (account) => account.configured,
        describeAccount: (account) =>
          describeAccountSnapshot({
            account,
            configured: account.configured,
            extra: {
              apiUrl: account.apiUrl,
              handle: account.handle,
              apiTokenSource: account.apiTokenSource,
            },
          }),
      },
      groups: {
        resolveRequireMention: ({ cfg, accountId, groupId }) => {
          const account = resolvePulseboardAccount({ cfg: cfg as CoreConfig, accountId });
          if (!groupId) {
            return true;
          }
          const match = resolvePulseboardBoardMatch({
            boards: account.config.boards,
            boardId: groupId,
          });
          return resolvePulseboardRequireMention({
            boardConfig: match.boardConfig,
            wildcardConfig: match.wildcardConfig,
          });
        },
        resolveToolPolicy: ({ cfg, accountId, groupId }) => {
          const account = resolvePulseboardAccount({ cfg: cfg as CoreConfig, accountId });
          if (!groupId) {
            return undefined;
          }
          const match = resolvePulseboardBoardMatch({
            boards: account.config.boards,
            boardId: groupId,
          });
          return match.boardConfig?.tools ?? match.wildcardConfig?.tools;
        },
      },
      messaging: {
        normalizeTarget: normalizePulseboardMessagingTarget,
        targetResolver: {
          looksLikeId: looksLikePulseboardTargetId,
          hint: "<!board|handle>",
        },
      },
      resolver: {
        resolveTargets: async ({ inputs, kind }) => {
          return inputs.map((input) => {
            const normalized = normalizePulseboardMessagingTarget(input);
            if (!normalized) {
              return {
                input,
                resolved: false,
                note: "invalid PulseBoard target",
              };
            }
            if (kind === "group") {
              const boardId = isBoardTarget(normalized) ? normalized : `!${normalized}`;
              return {
                input,
                resolved: true,
                id: boardId,
                name: boardId,
              };
            }
            if (isBoardTarget(normalized)) {
              return {
                input,
                resolved: false,
                note: "expected user target",
              };
            }
            return {
              input,
              resolved: true,
              id: normalized,
              name: normalized,
            };
          });
        },
      },
      directory: createChannelDirectoryAdapter({
        listPeers: async (params) => listPulseboardDirectoryPeersFromConfig(params),
        listGroups: async (params) => {
          const entries = await listPulseboardDirectoryBoardsFromConfig(params);
          return entries.map((entry) => ({ ...entry, name: entry.id }));
        },
      }),
      status: createComputedAccountStatusAdapter<ResolvedPulseboardAccount, PulseBoardProbe>({
        defaultRuntime: createDefaultChannelRuntimeState(DEFAULT_ACCOUNT_ID),
        buildChannelSummary: ({ account, snapshot }) => ({
          ...buildBaseChannelStatusSummary(snapshot),
          apiUrl: account.apiUrl,
          handle: account.handle,
          probe: snapshot.probe,
          lastProbeAt: snapshot.lastProbeAt ?? null,
        }),
        probeAccount: async ({ cfg, account, timeoutMs }) =>
          probePulseboard(cfg as CoreConfig, {
            accountId: account.accountId,
            timeoutMs,
          }),
        resolveAccountSnapshot: ({ account }) => ({
          accountId: account.accountId,
          name: account.name,
          enabled: account.enabled,
          configured: account.configured,
          extra: {
            apiUrl: account.apiUrl,
            handle: account.handle,
            apiTokenSource: account.apiTokenSource,
          },
        }),
      }),
      gateway: {
        startAccount: async (ctx) => {
          const account = ctx.account;
          const statusSink = createAccountStatusSink({
            accountId: ctx.accountId,
            setStatus: ctx.setStatus,
          });
          if (!account.configured) {
            throw new Error(
              `PulseBoard is not configured for account "${account.accountId}" (need apiUrl, apiToken, and handle in channels.pulseboard).`,
            );
          }
          ctx.log?.info(
            `[${account.accountId}] starting PulseBoard provider (${account.apiUrl}, handle=${account.handle})`,
          );
          await runStoppablePassiveMonitor({
            abortSignal: ctx.abortSignal,
            start: async () =>
              await monitorPulseboardProvider({
                accountId: account.accountId,
                config: ctx.cfg as CoreConfig,
                runtime: ctx.runtime,
                abortSignal: ctx.abortSignal,
                statusSink,
              }),
          });
        },
      },
    },
    pairing: {
      text: {
        idLabel: "pulseboardHandle",
        message: PAIRING_APPROVED_MESSAGE,
        normalizeAllowEntry: (entry) => normalizePulseboardAllowEntry(entry),
        notify: async ({ id, message }) => {
          const target = normalizePairingTarget(id);
          if (!target) {
            throw new Error(`invalid PulseBoard pairing id: ${id}`);
          }
          await sendMessagePulseboard(target, message);
        },
      },
    },
    security: {
      resolveDmPolicy: resolvePulseboardDmPolicy,
      collectWarnings: collectPulseboardSecurityWarnings,
    },
    outbound: {
      base: {
        deliveryMode: "direct",
        chunker: chunkTextForOutbound,
        chunkerMode: "markdown",
        // PulseBoard allows up to 4000 characters per post/message.
        textChunkLimit: 4000,
      },
      attachedResults: {
        channel: "pulseboard",
        sendText: async ({ cfg, to, text, accountId, replyToId }) =>
          await sendMessagePulseboard(to, text, {
            cfg: cfg as CoreConfig,
            accountId: accountId ?? undefined,
            replyTo: replyToId ?? undefined,
          }),
        sendMedia: async ({ cfg, to, text, mediaUrl, accountId, replyToId }) =>
          await sendMessagePulseboard(
            to,
            mediaUrl ? `${text}\n\nAttachment: ${mediaUrl}` : text,
            {
              cfg: cfg as CoreConfig,
              accountId: accountId ?? undefined,
              replyTo: replyToId ?? undefined,
            },
          ),
      },
    },
  });

