import { resolvePulseboardAccount } from "./accounts.js";
import { fetchPulseBoardMe } from "./client.js";
import type { CoreConfig, PulseBoardProbe } from "./types.js";

function formatError(err: unknown): string {
  if (err instanceof Error) {
    return err.message;
  }
  return typeof err === "string" ? err : JSON.stringify(err);
}

/**
 * Probe the PulseBoard API to verify connectivity and credential validity.
 *
 * Issues a GET /v1/me request and records round-trip latency. Returns a
 * PulseBoardProbe with `ok=true` on success or `error` on failure.
 */
export async function probePulseboard(
  cfg: CoreConfig,
  opts?: { accountId?: string; timeoutMs?: number },
): Promise<PulseBoardProbe> {
  const account = resolvePulseboardAccount({ cfg, accountId: opts?.accountId });
  const base: PulseBoardProbe = {
    ok: false,
    apiUrl: account.apiUrl,
    handle: account.handle,
  };

  if (!account.configured) {
    return {
      ...base,
      error: "missing apiUrl, apiToken, or handle",
    };
  }

  const controller = new AbortController();
  const timeoutHandle = setTimeout(
    () => controller.abort(),
    opts?.timeoutMs ?? 8_000,
  );

  const started = Date.now();
  try {
    const me = await fetchPulseBoardMe({
      apiUrl: account.apiUrl,
      apiToken: account.apiToken,
    });
    const elapsed = Date.now() - started;
    return {
      ...base,
      ok: true,
      latencyMs: elapsed,
      // Sanity-check: the reported handle should match what we configured.
      ...(me.handle !== account.handle && {
        note: `handle mismatch: expected "${account.handle}", got "${me.handle}"`,
      }),
    };
  } catch (err) {
    return {
      ...base,
      error: formatError(err),
    };
  } finally {
    clearTimeout(timeoutHandle);
  }
}

